var partition = function(head, x) {
    const lessHead = new ListNode(0);
    const geHead = new ListNode(0);
    let less = lessHead;
    let ge = geHead;
    let node = head;
    while (node) {
        if (node.val < x) {
            less.next = node;
            less = less.next;
        } else {
            ge.next = node;
            ge = ge.next;
        }
        node = node.next;
    }
    ge.next = null;
    less.next = geHead.next;
    return lessHead.next;
};
